var getFiles;

getFiles = require('./get-files');

module.exports = function(options) {
  var file, i, len, object, objects, ref, result, set, store;
  store = options.store;
  result = getFiles(options);
  objects = [];
  set = {};
  ref = result.files;
  for (i = 0, len = ref.length; i < len; i++) {
    file = ref[i];
    if (set[file] !== true) {
      set[file] = true;
      result = store.append(file);
      object = store.array.pop();
      if (Object.keys(object).length > 0) {
        objects.push(object);
      }
    }
  }
  return {
    objects: objects
  };
};

module.exports.scopes = ['global', 'system', 'user', 'local', 'each', 'all'];
